sql:
SELECT cinema_id, COUNT(DISTINCT movie_id) AS number_of_movies_screening
FROM showtimes
GROUP BY cinema_id;

SELECT COUNT(*) AS total_showtimes
FROM showtimes
WHERE cinema_id = 1;

SELECT COUNT(cinema_id) AS num_cinemas_in_visakapatnam
FROM cinemas
WHERE city IN ('Vizag Visakhapatnam', 'Vizag', 'Visakhapatnam');

SELECT customer_id, COUNT(*) AS total_bookings
FROM bookings
GROUP BY customer_id;

external_knowledge:
- 'Frequent travelers' refers to customers who have made more than one booking;
- 'Golden month' metaphorically refers to the period between September 1, 2023, and October 1, 2023;
- 'Voyages' in this context refer to bookings made by the customers;
- 'Average cost of their voyages' is the average booking cost for each customer.

sql:
SELECT COUNT(booking_id) AS total_bookings
FROM bookings
WHERE customer_id = 1;

SELECT COUNT(*) AS total_bookings
FROM bookings
WHERE booking_date = '2023-10-01';

external_knowledge:
- "Treasure chest" refers to the total revenue;
- "Gateway to films" refers to the specific cinema (cinema_id = 1);
- "Golden month of September" refers to the date range from September 1, 2023, to September 30, 2023.

sql:
SELECT AVG(total_cost) AS average_booking_cost
FROM bookings
WHERE booking_status = 'Confirmed';
